using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public sealed class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public sealed class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public sealed class TicketResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Scores { get; set; } = new();
}

public sealed class TrainingMetrics
{
    public double MicroAccuracy { get; set; }
    public double MacroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketModelService
{
    private readonly string _modelPath;
    private readonly string _dataPath;
    private readonly MLContext _mlContext;
    private TrainingMetrics? _lastMetrics;

    public TrainingMetrics? LastMetrics => _lastMetrics;

    public TicketModelService(IWebHostEnvironment env)
    {
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
        _mlContext = new MLContext(seed: 42);
    }

    public TrainingMetrics TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Featurize text columns and combine with Priority into a single Features vector
        var pipeline = _mlContext.Transforms.Text
                .FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
            .Append(_mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(split.TrainSet);
        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        _lastMetrics = new TrainingMetrics
        {
            MicroAccuracy = metrics.MicroAccuracy,
            MacroAccuracy = metrics.MacroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction
        };

        _mlContext.Model.Save(model, data.Schema, _modelPath);
        return _lastMetrics;
    }

    public string GetModelPath() => _modelPath;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private static readonly string[] Categories = ["Billing", "Technical", "General"];

    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly TicketModelService _modelService;
    private readonly ILogger<TicketClassifierController> _logger;

    public TicketClassifierController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        TicketModelService modelService,
        ILogger<TicketClassifierController> logger)
    {
        _predictionPool = predictionPool;
        _modelService = modelService;
        _logger = logger;
    }

    [HttpPost("predict")]
    public ActionResult<TicketResponse> Predict([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var scores = new Dictionary<string, float>();
        for (var i = 0; i < prediction.Score.Length && i < Categories.Length; i++)
        {
            scores[Categories[i]] = prediction.Score[i];
        }

        _logger.LogInformation(
            "Predicted category {Category} for ticket \"{Subject}\"",
            prediction.Category, request.Subject);

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Scores = scores
        });
    }

    [HttpPost("train")]
    public ActionResult<TrainingMetrics> Train()
    {
        var metrics = _modelService.TrainAndEvaluate();

        _logger.LogInformation(
            "Model trained — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}",
            metrics.MicroAccuracy, metrics.MacroAccuracy);

        return Ok(metrics);
    }

    [HttpGet("metrics")]
    public ActionResult<TrainingMetrics> GetMetrics()
    {
        var metrics = _modelService.LastMetrics;
        if (metrics is null)
            return NotFound("No training metrics available. Call POST /api/ticketclassifier/train first.");

        return Ok(metrics);
    }
}

